module SidebarHelper
  def sidebar_link(label, path, icon: nil)
    active = request.path.start_with?(path)
    classes = "flex items-center gap-3 px-3 py-2 rounded-lg text-sm transition-colors "
    classes += active ? "bg-gray-800 text-white" : "text-gray-300 hover:bg-gray-800 hover:text-white"

    link_to path, class: classes do
      concat(sidebar_icon(icon)) if icon
      concat(content_tag(:span, label))
    end
  end

